firmware_template.source:
#include "ens160.h"
#include <Wire.h>
#include <ScioSense_ENS160.h>
static ScioSense_ENS160 ens(ENS160_I2CADDR_1);
static uint8_t _aqi=0;static uint16_t _tvoc=0,_eco2=0;static unsigned long _l=0;
void ens160_setup(){Wire.begin();ens.begin();ens.setMode(ENS160_OPMODE_STD);Serial.println("[ens160] OK");}
void ens160_loop(){if(millis()-_l<1000)return;_l=millis();if(ens.available()){ens.measure(true);_aqi=ens.getAQI();_tvoc=ens.getTVOC();_eco2=ens.geteCO2();}}
uint8_t ens160_get_aqi(){return _aqi;}
uint16_t ens160_get_tvoc(){return _tvoc;}
uint16_t ens160_get_eco2(){return _eco2;}
